class Solution:
    def uniformArray(self, nums1):
        n = len(nums1)
        if n == 1:
            return True
        order = sorted(range(n), key=lambda i: nums1[i])
        target = nums1[order[0]] % 2
        seen_odd = (nums1[order[0]] % 2 == 1)
        for idx in range(1, n):
            v = nums1[order[idx]]
            p = v % 2
            if p != target and not seen_odd:
                return False
            if p == 1:
                seen_odd = True
        return True

