var uniformArray = function(nums1) {
    const n = nums1.length;
    if (n === 1) return true;
    const order = Array.from({length: n}, (_, i) => i).sort((a, b) => nums1[a] - nums1[b]);
    const target = nums1[order[0]] % 2;
    let seenOdd = (nums1[order[0]] % 2 === 1);
    for (let idx = 1; idx < n; idx++) {
        const v = nums1[order[idx]];
        const p = v % 2;
        if (p !== target && !seenOdd) return false;
        if (p === 1) seenOdd = true;
    }
    return true;
};
